SELECT count(*) FROM kind_type, title, movie_info, movie_keyword, movie_companies, cast_info, name, aka_name, info_type WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_info.info_type_id = info_type.id;